9	ciphertext_t public_key_t::encrypt(mem_t plain, mem_t label) const {
10	  const auto& curve = Q.get_curve();
11	
12	  buf_t iv = gen_random(iv_size);
13	  bn_t r = curve.get_random_value();
14	  bn_t s = curve.get_random_value();
15	  return encrypt(plain, label, r, s, iv);
16	}
