43	error_t ciphertext_t::verify(const public_key_t& pub_key, mem_t label) const {
44	  error_t rv = UNINITIALIZED_ERROR;
45	  const ecc_point_t& Gamma = pub_key.Gamma;
46	  const ecc_point_t& Q = pub_key.Q;
47	  const auto& curve = Gamma.get_curve();
48	  const auto& G = curve.generator();
49	  const mod_t& q = curve.order();
50	
51	  if (label != L) return coinbase::error(E_CRYPTO, "ciphertext_t::verify: label mismatch");
52	  if (iv.size() != iv_size) return coinbase::error(E_CRYPTO, "ciphertext_t::verify: invalid iv");
53	  if (!q.is_in_range(e) || !q.is_in_range(f)) return coinbase::error(E_CRYPTO, "ciphertext_t::verify: invalid scalar");
54	  if (rv = curve.check(R1)) return coinbase::error(rv, "ciphertext_t::verify: check R1 failed");
55	  if (rv = curve.check(R2)) return coinbase::error(rv, "ciphertext_t::verify: check R2 failed");
56	
57	  if (Gamma != ro::hash_curve(mem_t("TDH2-Gamma"), Q, pub_key.sid).curve(Q.get_curve()))
58	    return coinbase::error(E_CRYPTO, "ciphertext_t::verify: Gamma mismatch");
59	
60	  ecc_point_t W1 = f * G - e * R1;
61	  ecc_point_t W2 = f * Gamma - e * R2;
62	
63	  bn_t e_test = ro::hash_number(c, label, R1, W1, R2, W2, iv).mod(q);
64	  if (e_test != e) return coinbase::error(E_CRYPTO);
65	  return SUCCESS;
66	}
