68	error_t private_share_t::decrypt(const ciphertext_t& ciphertext, mem_t label,
69	                                 partial_decryption_t& partial_decryption) const {
70	  error_t rv = UNINITIALIZED_ERROR;
71	  const auto& curve = pub_key.Q.get_curve();
72	  if (rv = ciphertext.verify(pub_key, label)) return rv;
73	  const ecc_point_t& R1 = ciphertext.R1;
74	
75	  const auto& G = curve.generator();
76	  const mod_t& q = curve.order();
77	
78	  ecc_point_t& Xi = partial_decryption.Xi;
79	  bn_t& ei = partial_decryption.ei;
80	  bn_t& fi = partial_decryption.fi;
81	
82	  partial_decryption.rid = rid;
83	  Xi = x * R1;
84	
85	  bn_t si = curve.get_random_value();
86	  ecc_point_t Yi = si * R1;
87	  ecc_point_t Zi = si * G;
88	
89	  ei = ro::hash_number(Xi, Yi, Zi).mod(q);
90	  MODULO(q) fi = si + x * ei;
91	  return SUCCESS;
92	}
