53	error_t deserialize_private_share(mem_t in, coinbase::crypto::tdh2::private_share_t& out) {
54	  private_share_blob_v1_t blob;
55	  error_t rv = coinbase::convert(blob, in);
56	  if (rv) return rv;
57	  if (blob.version != private_share_blob_version_v1) return coinbase::error(E_FORMAT, "unsupported private share blob");
58	
59	  const auto cid = static_cast<curve_id>(blob.curve);
60	  if (cid == curve_id::ed25519) return coinbase::error(E_FORMAT, "invalid private share curve");
61	  const auto curve = to_internal_curve(cid);
62	  if (!curve.valid()) return coinbase::error(E_FORMAT, "invalid private share curve");
63	
64	  if (blob.rid <= 0) return coinbase::error(E_FORMAT, "invalid private share blob");
65	  if (curve.order().is_in_range(blob.x) == false) return coinbase::error(E_FORMAT, "invalid private share blob");
66	
67	  if (const error_t pk_rv = validate_public_key(blob.pub_key)) return pk_rv;
68	  if (blob.pub_key.Q.get_curve() != curve) return coinbase::error(E_FORMAT, "invalid private share blob");
69	
70	  out.rid = blob.rid;
71	  out.x = blob.x;
72	  out.pub_key = blob.pub_key;
73	  return SUCCESS;
74	}
