107	error_t dkg_additive(const coinbase::api::job_mp_t& job, curve_id curve, buf_t& public_key,
108	                     std::vector<buf_t>& public_shares, buf_t& private_share, buf_t& sid) {
109	  error_t rv = validate_job_mp(job);
110	  if (rv) return rv;
111	
112	  if (curve == curve_id::ed25519) return coinbase::error(E_BADARG, "unsupported curve");
113	  const auto icurve = to_internal_curve(curve);
114	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
115	
116	  coinbase::mpc::job_mp_t mpc_job = to_internal_job(job);
117	  coinbase::mpc::eckey::key_share_mp_t key;
118	
119	  public_key.free();
120	  private_share.free();
121	  sid.free();
122	  public_shares.clear();
123	
124	  rv = coinbase::mpc::eckey::key_share_mp_t::dkg(mpc_job, icurve, key, sid);
125	  if (rv) return rv;
126	
127	  rv = serialize_public_outputs(job, key, sid, public_key, public_shares);
128	  if (rv) return rv;
129	
130	  // Deserialize the public key blob so we can embed the exact serialized form in the private share.
131	  coinbase::crypto::tdh2::public_key_t pk;
132	  rv = pk.from_bin(public_key);
133	  if (rv) return rv;
134	
135	  return serialize_private_share(curve, job.self, key.x_share, pk, private_share);
136	}
