238	error_t combine_additive(mem_t public_key, const std::vector<mem_t>& public_shares, mem_t label,
239	                         const std::vector<mem_t>& partial_decryptions, mem_t ciphertext, buf_t& plaintext) {
240	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(public_key, "public_key",
241	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
242	    return rv;
243	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
244	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
245	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
246	    return rv;
247	  if (const error_t rv = coinbase::api::detail::validate_mem_vec_arg_max_size(
248	          public_shares, "public_shares", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
249	    return rv;
250	  if (const error_t rv = coinbase::api::detail::validate_mem_vec_arg_max_size(
251	          partial_decryptions, "partial_decryptions", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
252	    return rv;
253	
254	  if (public_shares.size() != partial_decryptions.size())
255	    return coinbase::error(E_BADARG, "public_shares and partial_decryptions size mismatch");
256	
257	  coinbase::crypto::tdh2::public_key_t pk;
258	  error_t rv = pk.from_bin(public_key);
259	  if (rv) return rv;
260	  if (rv = validate_public_key(pk)) return rv;
261	
262	  coinbase::crypto::tdh2::ciphertext_t ct;
263	  rv = coinbase::convert(ct, ciphertext);
264	  if (rv) return rv;
265	
266	  auto curve = pk.Q.get_curve();
267	  if (!curve.valid()) return coinbase::error(E_FORMAT, "public key missing curve");
268	
269	  coinbase::crypto::tdh2::pub_shares_t Qi;
270	  Qi.reserve(public_shares.size());
271	  for (const auto& m : public_shares) {
272	    coinbase::crypto::ecc_point_t P;
273	    rv = P.from_bin(curve, m);
274	    if (rv) return rv;
275	    Qi.emplace_back(std::move(P));
276	  }
277	
278	  coinbase::crypto::tdh2::partial_decryptions_t partials;
279	  partials.resize(partial_decryptions.size());
280	  for (size_t i = 0; i < partial_decryptions.size(); i++) {
281	    rv = coinbase::convert(partials[i], partial_decryptions[i]);
282	    if (rv) return rv;
283	  }
284	
285	  return coinbase::crypto::tdh2::combine_additive(pk, Qi, label, partials, ct, plaintext);
286	}
